   714  // CleanVerb returns a normalized verb, so that it is easy to tell WATCH from
   715  // LIST, APPLY from PATCH and CONNECT from others.
   716  func CleanVerb(verb string, request *http.Request, requestInfo *request.RequestInfo) string {
   717          reportedVerb := verb
   718          if suggestedVerb := getVerbIfWatch(request); suggestedVerb == "WATCH" {
   719                  reportedVerb = "WATCH"
   720          }
   721          // normalize the legacy WATCHLIST to WATCH to ensure users aren't surprised by metrics
   722          if verb == "WATCHLIST" {
   723                  reportedVerb = "WATCH"
   724          }
   725          if verb == "PATCH" && request.Header.Get("Content-Type") == string(types.ApplyPatchType) {
   726                  reportedVerb = "APPLY"
   727          }
   728          if requestInfo != nil && requestInfo.IsResourceRequest && len(requestInfo.Subresource) > 0 && validConnectRequests.Has(requestInfo.Subresource) {
   729                  reportedVerb = "CONNECT"
   730          }
   731          return reportedVerb
   732  }
