   737  // after an unsuccessful attempt of moving it to RequestInfo
   738  //
   739  // see: https://github.com/kubernetes/kubernetes/pull/120520
   740  func determineRequestNamespaceAndName(ctx context.Context, opts *metainternalversion.ListOptions) (namespace, name string) {
   741          if requestNamespace, ok := request.NamespaceFrom(ctx); ok && len(requestNamespace) > 0 {
   742                  namespace = requestNamespace
   743          } else if opts != nil && opts.FieldSelector != nil {
   744                  if selectorNamespace, ok := opts.FieldSelector.RequiresExactMatch("metadata.namespace"); ok {
   745                          namespace = selectorNamespace
   746                  }
   747          }
   748          if requestInfo, ok := request.RequestInfoFrom(ctx); ok && requestInfo != nil && len(requestInfo.Name) > 0 {
   749                  name = requestInfo.Name
   750          } else if opts != nil && opts.FieldSelector != nil {
   751                  if selectorName, ok := opts.FieldSelector.RequiresExactMatch("metadata.name"); ok {
   752                          name = selectorName
   753                  }
   754          }
   755          return
   756  }
