   758  // cleanVerb additionally ensures that unknown verbs don't clog up the metrics.
   759  func cleanVerb(verb, suggestedVerb string, request *http.Request, requestInfo *request.RequestInfo) string {
   760          // CanonicalVerb (being an input for this function) doesn't handle correctly the
   761          // deprecated path pattern for watch of:
   762          //   GET /api/{version}/watch/{resource}
   763          // We correct it manually based on the pass verb from the installer.
   764          if suggestedVerb == "WATCH" || suggestedVerb == "WATCHLIST" {
   765                  return "WATCH"
   766          }
   767          reportedVerb := CleanVerb(verb, request, requestInfo)
   768          if validRequestMethods.Has(reportedVerb) {
   769                  return reportedVerb
   770          }
   771          return OtherRequestMethod
   772  }
