   774  // getVerbIfWatch additionally ensures that GET or List would be transformed to WATCH
   775  func getVerbIfWatch(req *http.Request) string {
   776          if strings.ToUpper(req.Method) == "GET" || strings.ToUpper(req.Method) == "LIST" {
   777                  // see apimachinery/pkg/runtime/conversion.go Convert_Slice_string_To_bool
   778                  if values := req.URL.Query()["watch"]; len(values) > 0 {
   779                          if value := strings.ToLower(values[0]); value != "0" && value != "false" {
   780                                  return "WATCH"
   781                          }
   782                  }
   783          }
   784          return ""
   785  }
